#ifndef _KERNEL_H_
#define _KERNEL_H_

__kernel void
BFS_1( Node* x_0, int* g_graph_edges, char* g_graph_mask, char* elem_1, char *v_3, int* g_cost, int tmp_2) 
{
	int tid = get_global_id(0);
	if( tid < tmp_2 && g_graph_mask[tid])
	{
		g_graph_mask[tid]=0;
		for(int i=x_0[tid].starting; (x_0[tid].no_of_edges + x_0[tid].starting) > i; i++)
			{
			int v_4 = g_graph_edges[i];
			if(!v_3[v_4])
				{
				g_cost[v_4]=g_cost[tid]+1;
				elem_1[v_4]=1;
				}
			}
	}
}

__kernel void
BFS_2( char* g_graph_mask, char *g_updating_graph_mask, char* g_graph_visited, char *g_over, int no_of_nodes)
{
	int tid = get_global_id(0);
	if( tid < no_of_nodes && g_updating_graph_mask[tid])
	{

		g_graph_mask[tid]=1;
		g_graph_visited[tid]=1;
		g_over[0]=1;
		g_updating_graph_mask[tid]=0;
	}
}

#endif
